import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import Header from './components/Header';
import { Tab, HomePageData, MusicPageData, ToolsPageData, AboutPageData, CommunityPageData, LibraryPageData, GamingPageData } from './types';
import { fetchManifest, fetchAllPagesData, fetchRandomBackgroundUrl, SiteData, Manifest, ManifestUISettings } from './services/contentService';
import HomePage from './pages/HomePage';
import MusicPage from './pages/MusicPage';
import ToolsPage from './pages/ToolsPage';
import AboutPage from './pages/AboutPage';
import CommunityPage from './pages/CommunityPage';
import LibraryPage from './pages/LibraryPage';
import GamingPage from './pages/GamingPage';
import DebugMenu from './components/DebugMenu';

// A generic content display component.
const PageContent: React.FC<{ data: any; title?: string; message?: string[] }> = ({ data, title, message }) => {
  const displayTitle = data?.title || title || 'Loading...';
  const displayParagraphs = data?.paragraphs || message || [];

  return (
    <div className="p-6 sm:p-8 bg-gray-900/50 backdrop-blur-lg rounded-2xl shadow-2xl ring-1 ring-white/10">
      <h1 className="text-3xl sm:text-4xl font-bold mb-4 text-amber-400">{displayTitle}</h1>
      <div className="text-gray-300 leading-relaxed space-y-4">
        {displayParagraphs.map((p, index) => <p key={index}>{p}</p>)}
      </div>
    </div>
  );
};

// --- Icon Components ---
const RefreshIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M4 4v5h5M20 20v-5h-5M4 4l1.5 1.5A9 9 0 0120.5 11M20 20l-1.5-1.5A9 9 0 003.5 13" />
    </svg>
);

const HideIcon = () => ( // This is the OPEN eye icon
  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
    <path strokeLinecap="round" strokeLinejoin="round" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
  </svg>
);

const ShowIcon = () => ( // This is the SLASHED eye icon
  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.05 10.05 0 01-4.125 5.825m0 0l3.59 3.59M21 21L3 3" />
  </svg>
);

const BlurIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M5 3v4M3 5h4M5 17v4m-2-2h4m11-12v4m2-2h-4m2 12h-4m4 2v-4M9 5a2 2 0 00-2 2v10a2 2 0 002 2h6a2 2 0 002-2V7a2 2 0 00-2-2H9z" />
    </svg>
);


const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.Home);

  const [manifest, setManifest] = useState<Manifest | null>(null);
  const [siteData, setSiteData] = useState<SiteData | null>(null);

  const [backgrounds, setBackgrounds] = useState<[string, string]>(['', '']);
  const [activeBgIndex, setActiveBgIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);

  const [isBlurSliderVisible, setIsBlurSliderVisible] = useState(false);
  const [showDebugContent, setShowDebugContent] = useState(false);

  // States for UI Settings
  const [isUiVisible, setIsUiVisible] = useState<boolean>(true);
  const [uiSettings, setUiSettings] = useState<ManifestUISettings | undefined>(undefined);

  const intervalRef = useRef<number | null>(null);
  const backgroundsRef = useRef(backgrounds);
  const isTransitioningRef = useRef(isTransitioning);
  const activeTabRef = useRef(activeTab);

  // Refs for background change logic
  const prevTab = useRef<Tab>(activeTab);
  const initialLoad = useRef(true);

  useEffect(() => {
    backgroundsRef.current = backgrounds;
  }, [backgrounds]);

  useEffect(() => {
    isTransitioningRef.current = isTransitioning;
  }, [isTransitioning]);

  useEffect(() => {
    activeTabRef.current = activeTab;
  }, [activeTab]);

  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const isDebug = useMemo(() => manifest?.cfg.debug.on || false, [manifest]);

  // Handle URL parameters for deep linking
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const tabParam = params.get('tab');
    if (tabParam && Object.values(Tab).includes(tabParam as Tab)) {
      setActiveTab(tabParam as Tab);
    }
  }, []);

  // Dynamic Styles Effect
  useEffect(() => {
    if (!uiSettings) return;

    const { layout, effects } = uiSettings;
    const css = `
      :root {
        --padding-base: ${layout.padding_base_unit_px}px;
        --main-content-padding: calc(var(--padding-base) * ${layout.main_content_padding_multiplier});
        --panel-padding: calc(var(--padding-base) * ${layout.panel_padding_multiplier});
        --panel-radius: ${layout.panel_border_radius_px}px;
        --panel-ring-color: rgba(255, 255, 255, ${layout.panel_ring_opacity_percent / 100});

        --background-blur-amount: ${effects.background_blur_px}px;
        --header-blur-amount: ${effects.header_blur_px}px;
        --footer-blur-amount: ${effects.footer_blur_px}px;
        --hud-blur-amount: ${effects.hud_blur_px}px;

        --glow-color-primary-rgb: ${effects.glow_primary_color_rgba};
        --glow-color-primary: rgba(var(--glow-color-primary-rgb), ${effects.glow_primary_opacity_percent / 100});
      }
    `;
    let styleTag = document.getElementById('dynamic-styles');
    if (!styleTag) {
      styleTag = document.createElement('style');
      styleTag.id = 'dynamic-styles';
      document.head.appendChild(styleTag);
    }
    styleTag.innerHTML = css;
  }, [uiSettings]);


  // Global Glow Effect Handler
  useEffect(() => {
    if (!uiSettings?.effects.enable_glow_effect) {
        document.body.classList.add('glow-disabled');
        return; // Skip adding listener if disabled
    }
    document.body.classList.remove('glow-disabled');

    const handleGlobalMouseMove = (e: MouseEvent) => {
        const target = e.target as HTMLElement;
        const glowingElement = target.closest('.glow-on-hover');
        if (glowingElement) {
            const rect = glowingElement.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;
            (glowingElement as HTMLElement).style.setProperty('--mouse-x', `${x}px`);
            (glowingElement as HTMLElement).style.setProperty('--mouse-y', `${y}px`);
        }
    };

    document.addEventListener('mousemove', handleGlobalMouseMove);
    return () => {
        document.removeEventListener('mousemove', handleGlobalMouseMove);
        document.body.classList.remove('glow-disabled'); // Clean up on unmount
    };
  }, [uiSettings?.effects.enable_glow_effect]);

  const loadNextBackground = useCallback(() => {
    if (isTransitioningRef.current || !manifest || !uiSettings) return;

    setIsTransitioning(true);

    fetchRandomBackgroundUrl(manifest, activeTabRef.current, uiSettings.backgrounds.per_page_switching).then(url => {
      if (!url || backgroundsRef.current.includes(url)) {
        setIsTransitioning(false);
        return; 
      }

      setActiveBgIndex(prevIndex => {
        const inactiveIndex = 1 - prevIndex;
        setBackgrounds(prevBgs => {
          const newBgs: [string, string] = [prevBgs[0], prevBgs[1]];
          newBgs[inactiveIndex] = url;
          return newBgs;
        });
        return inactiveIndex;
      });

      setTimeout(() => {
          setIsTransitioning(false);
      }, 2000); // Corresponds to the transition duration

    }).catch(() => {
        setIsTransitioning(false);
    });
  }, [manifest, uiSettings]);

  const startBgInterval = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);

    if (!uiSettings || !uiSettings.backgrounds.allow_auto_change) {
        return;
    }

    const min = (uiSettings.backgrounds.change_interval_min_seconds || 20) * 1000;
    const max = (uiSettings.backgrounds.change_interval_max_seconds || 40) * 1000;

    const effectiveMin = min;
    const effectiveMax = Math.max(min, max);

    const randomDelay = Math.floor(Math.random() * (effectiveMax - effectiveMin + 1)) + effectiveMin;

    intervalRef.current = window.setInterval(loadNextBackground, randomDelay);
  }, [loadNextBackground, uiSettings]);

  // Effect to fetch initial manifest and apply settings
  useEffect(() => {
    const loadInitialData = async () => {
      setLoading(true);
      setError(null);
      try {
        const manifestData = await fetchManifest();
        setManifest(manifestData);

        // --- Apply settings from manifest ---
        if (manifestData.settings) {
          const { site, content, ui } = manifestData.settings;

          // Only use default_tab if there's no tab in the URL
          const params = new URLSearchParams(window.location.search);
          if (!params.get('tab') && site?.default_tab && Object.values(Tab).includes(site.default_tab as Tab)) {
            setActiveTab(site.default_tab as Tab);
          }

          if (ui) {
            setUiSettings(ui);
            setIsUiVisible(ui.show_ui_on_load);
          }
          if (content) {
            setShowDebugContent(content.show_debug_items_by_default);
          }
        }
        // --- End settings application ---

        const allData = await fetchAllPagesData(manifestData);
        setSiteData(allData);
      } catch (err) {
        const errorMessage = err instanceof Error ? err.message : 'An unknown error occurred';
        setError(errorMessage);
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    loadInitialData();
  }, []);

  // Comprehensive effect to manage all background changes
  useEffect(() => {
      if (!manifest || !uiSettings) {
          return; // Wait for manifest and settings to load
      }

      let shouldLoadNewBackground = false;

      // 1. Initial Load: Always load a background on the very first run.
      if (initialLoad.current) {
          shouldLoadNewBackground = true;
          initialLoad.current = false;
      }

      // 2. Tab Changed: Check if tab is different and if the setting is enabled.
      if (prevTab.current !== activeTab) {
          if (uiSettings.backgrounds.per_page_switching) {
              shouldLoadNewBackground = true;
          }
          prevTab.current = activeTab;
      }

      if (shouldLoadNewBackground) {
          loadNextBackground();
      }

      // 3. Interval Management: Always restart the interval when settings could have changed.
      // This ensures the auto-change setting is respected immediately.
      startBgInterval();

      // 4. Cleanup: Clear interval on unmount or before the effect re-runs.
      return () => {
          if (intervalRef.current) {
              clearInterval(intervalRef.current);
          }
      };
  }, [activeTab, manifest, uiSettings, loadNextBackground, startBgInterval]);

  const handleNextImageClick = useCallback(() => {
    if (isTransitioning) return;
    loadNextBackground();
    startBgInterval(); // Reset interval on manual change
  }, [loadNextBackground, startBgInterval, isTransitioning]);

  const renderContent = () => {
    const simplePageWrapper = (content: React.ReactNode) => (
      <div className="h-full overflow-y-auto p-4 sm:p-6 lg:p-8 flex items-center justify-center">
        <div className="w-full max-w-3xl">
          {content}
        </div>
      </div>
    );

    if (loading) {
      return simplePageWrapper(
        <PageContent 
          data={null} 
          title="Loading ZIKYinc..." 
          message={["Fetching the latest content from our repositories. Please stand by."]} 
        />
      );
    }

    if (error) {
       return simplePageWrapper(
        <PageContent 
          data={null}
          title="Error"
          message={[`Failed to load site content: ${error}`]}
        />
      );
    }

    const currentPageData = siteData ? siteData[activeTab] : null;
    if (!currentPageData) {
      return simplePageWrapper(
         <PageContent 
          data={null}
          title="Content Not Found"
          message={[`We couldn't find any content for the ${activeTab} section.`]}
        />
      );
    }

    switch (activeTab) {
      case Tab.Home:
        return <HomePage data={currentPageData as HomePageData} manifest={manifest} />;
      case Tab.Music:
        return <MusicPage data={currentPageData as MusicPageData} manifest={manifest} showDebugContent={showDebugContent} />;
      case Tab.Tools:
        return <ToolsPage data={currentPageData as ToolsPageData} manifest={manifest} showDebugContent={showDebugContent} />;
      case Tab.About:
        return <AboutPage data={currentPageData as AboutPageData} manifest={manifest} />;
      case Tab.Community:
        return <CommunityPage data={currentPageData as CommunityPageData} manifest={manifest} showDebugContent={showDebugContent} />;
      case Tab.Library:
        return <LibraryPage data={currentPageData as LibraryPageData} manifest={manifest} />;
      case Tab.Gaming:
        return <GamingPage data={currentPageData as GamingPageData} manifest={manifest} showDebugContent={showDebugContent} />;
      default:
        return simplePageWrapper(<PageContent data={currentPageData} />);
    }
  };

  return (
    <>
      {/* Background Image Containers for cross-fade effect */}
      <div 
        className="fixed inset-0 bg-cover bg-center bg-fixed transition-opacity duration-[2000ms] ease-in-out glow-on-hover glow-bg"
        style={{ backgroundImage: `url(${backgrounds[0]})`, opacity: activeBgIndex === 0 ? 1 : 0 }}
        aria-hidden="true"
      />
      <div 
        className="fixed inset-0 bg-cover bg-center bg-fixed transition-opacity duration-[2000ms] ease-in-out glow-on-hover glow-bg"
        style={{ backgroundImage: `url(${backgrounds[1]})`, opacity: activeBgIndex === 1 ? 1 : 0 }}
        aria-hidden="true"
      />

      <div 
        className="relative h-screen bg-transparent font-sans"
        aria-live="polite"
      >
        <div 
            className="h-full w-full bg-black/30 flex flex-col overflow-hidden"
            style={{ 
                backdropFilter: isUiVisible ? `blur(var(--background-blur-amount))` : 'none', 
                transition: 'backdrop-filter 0.5s ease-in-out' 
            }}
        >
          {isUiVisible && (
            <Header 
              activeTab={activeTab} 
              setActiveTab={setActiveTab} 
              manifest={manifest}
              isDebug={isDebug}
            />
          )}
          <main 
             className={`max-w-screen-2xl mx-auto w-full flex-grow transition-opacity duration-500 overflow-hidden ${isUiVisible ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
             style={{ paddingLeft: 'var(--main-content-padding)', paddingRight: 'var(--main-content-padding)'}}
             aria-hidden={!isUiVisible}
          >
            <div key={activeTab} className="animate-fade-in-up h-full">
              {renderContent()}
            </div>
          </main>
          {isUiVisible && (
              <footer className="w-full text-center p-4 border-t border-white/10" style={{
                backgroundColor: 'rgba(17, 24, 39, 0.5)', /* bg-gray-900/50 */
                backdropFilter: `blur(var(--footer-blur-amount))`
              }}>
                  <h2 className="text-amber-500 font-semibold tracking-wide">ZIKYinc 2024 - London UK</h2>
              </footer>
          )}
        </div>
      </div>

      {/* Persistent HUD Controls */}
      <div className="fixed bottom-4 right-4 z-[60] flex flex-col items-end gap-3">
            {isBlurSliderVisible && isUiVisible && uiSettings && (
                <div className="p-3 rounded-lg ring-1 ring-white/10 w-48 animate-fade-in-up" style={{
                  backgroundColor: 'rgba(17, 24, 39, 0.6)', /* bg-gray-900/60 */
                  backdropFilter: `blur(var(--hud-blur-amount))`
                }}>
                    <label htmlFor="blur-slider" className="text-xs text-amber-200 block mb-2">Background Blur</label>
                    <input
                        id="blur-slider"
                        type="range"
                        min="0"
                        max="40"
                        step="1"
                        value={uiSettings.effects.background_blur_px}
                        onChange={(e) => setUiSettings({
                            ...uiSettings,
                            effects: { ...uiSettings.effects, background_blur_px: Number(e.target.value) }
                        })}
                        className="w-full h-2 rounded-lg appearance-none cursor-pointer"
                    />
                </div>
            )}
            <div className="flex space-x-3">
                 <button
                    onClick={() => setIsBlurSliderVisible(!isBlurSliderVisible)}
                    className="p-3 text-amber-300 rounded-full ring-1 ring-white/10 shadow-lg hover:bg-gray-900/80 hover:text-amber-400 transition-all duration-300 focus:outline-none focus-visible:ring-2 focus-visible:ring-amber-500"
                    aria-label="Toggle blur controls"
                    aria-expanded={isBlurSliderVisible}
                    style={{
                      backgroundColor: 'rgba(17, 24, 39, 0.5)', /* bg-gray-900/50 */
                      backdropFilter: `blur(var(--hud-blur-amount))`
                    }}
                 >
                    <BlurIcon />
                 </button>
                 <button
                    onClick={handleNextImageClick}
                    disabled={isTransitioning}
                    className="p-3 text-amber-300 rounded-full ring-1 ring-white/10 shadow-lg hover:bg-gray-900/80 hover:text-amber-400 transition-all duration-300 focus:outline-none focus-visible:ring-2 focus-visible:ring-amber-500 disabled:opacity-50 disabled:cursor-not-allowed"
                    aria-label="Next background image"
                    style={{
                      backgroundColor: 'rgba(17, 24, 39, 0.5)', /* bg-gray-900/50 */
                      backdropFilter: `blur(var(--hud-blur-amount))`
                    }}
                 >
                    <RefreshIcon />
                 </button>
                 <button
                    onClick={() => setIsUiVisible(!isUiVisible)}
                    className="p-3 text-amber-300 rounded-full ring-1 ring-white/10 shadow-lg hover:bg-gray-900/80 hover:text-amber-400 transition-all duration-300 focus:outline-none focus-visible:ring-2 focus-visible:ring-amber-500"
                    aria-label={isUiVisible ? "Hide interface to show background" : "Show user interface"}
                    style={{
                      backgroundColor: 'rgba(17, 24, 39, 0.5)', /* bg-gray-900/50 */
                      backdropFilter: `blur(var(--hud-blur-amount))`
                    }}
                 >
                    {isUiVisible ? <ShowIcon /> : <HideIcon />}
                 </button>
            </div>
      </div>

      {/* Debug Menu */}
      {isDebug && <DebugMenu manifest={manifest} siteData={siteData} uiSettings={uiSettings} setUiSettings={setUiSettings} />}
    </>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { ToolsPageData, ToolsSideTab, Tool, ToolDetail, WebToolDetail } from '../types';
import { Manifest } from '../services/contentService';
import { fetchFromGitHubRaw } from '../modules/io/import-utils';
import SideNav from '../components/SideNav';
import IntroductionTab from '../components/music/IntroductionTab';
import SearchAndFilter from '../components/SearchAndFilter';
import ViewSwitcher, { ViewMode } from '../components/ViewSwitcher';
import ToolCard from '../components/tools/ToolCard';
import ToolDetailView from '../components/tools/ToolDetailView';
import ListView from '../components/music/ListView';
import ToolLauncher from '../components/tools/ToolLauncher';

interface ToolsPageProps {
  data: ToolsPageData;
  manifest: Manifest | null;
  showDebugContent: boolean;
}

const sideTabs: ToolsSideTab[] = [
  ToolsSideTab.Introduction,
  ToolsSideTab.AllTools,
  ToolsSideTab.WebTools,
  ToolsSideTab.WindowsTools,
  ToolsSideTab.Scripts,
  ToolsSideTab.AITools,
];

const SESSION_STORAGE_KEY = 'zikyinc_tools_active_tab';

const ToolsPage: React.FC<ToolsPageProps> = ({ data, manifest, showDebugContent }) => {
  const [activeTab, setActiveTab] = useState<ToolsSideTab>(() => {
    const savedTab = sessionStorage.getItem(SESSION_STORAGE_KEY);
    return (savedTab as ToolsSideTab) || ToolsSideTab.Introduction;
  });

  const [searchTerm, setSearchTerm] = useState('');
  const [tagFilter, setTagFilter] = useState('All');
  const [viewMode, setViewMode] = useState<ViewMode>('card');

  const [selectedItemLink, setSelectedItemLink] = useState<string | null>(null);
  const [detailData, setDetailData] = useState<ToolDetail | null>(null);
  const [isLoadingDetail, setIsLoadingDetail] = useState(false);
  const [detailError, setDetailError] = useState<string | null>(null);

  // App Launcher State
  const [launchedTool, setLaunchedTool] = useState<WebToolDetail | null>(null);
  const [isLaunching, setIsLaunching] = useState(false);

  // Guard clause for missing data
  if (!data) {
    return (
      <div className="p-8 text-center text-amber-400">
        <h2 className="text-2xl font-bold">Tools page content is not available.</h2>
      </div>
    );
  }

  // Handle URL deep links for launching tools
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const launchPath = params.get('launch');
    if (launchPath) {
      handleLaunchApp(launchPath);
    }
  }, [manifest]);

  useEffect(() => {
    sessionStorage.setItem(SESSION_STORAGE_KEY, activeTab);
    setSelectedItemLink(null);
    setDetailData(null);
  }, [activeTab]);

  useEffect(() => {
    if (!selectedItemLink || !manifest) return;
    const fetchDetailData = async () => {
      setIsLoadingDetail(true);
      setDetailError(null);
      try {
        const { user, repo, branch } = manifest.git;
        const content = await fetchFromGitHubRaw(user, repo, branch, selectedItemLink);
        setDetailData(JSON.parse(content));
      } catch (err) {
        setDetailError(err instanceof Error ? err.message : 'Failed to load details.');
        console.error(err);
      } finally {
        setIsLoadingDetail(false);
      }
    };
    fetchDetailData();
  }, [selectedItemLink, manifest]);

  const handleViewDetails = useCallback((link: string) => {
    setSelectedItemLink(link);
  }, []);

  const handleBackToList = useCallback(() => {
    setSelectedItemLink(null);
    setDetailData(null);
    setDetailError(null);
  }, []);

  const handleLaunchApp = useCallback(async (link: string) => {
    if (!manifest) return;
    setIsLaunching(true);
    try {
      const { user, repo, branch } = manifest.git;
      const content = await fetchFromGitHubRaw(user, repo, branch, link);
      const detail = JSON.parse(content);
      if (detail.category === 'Web Tool') {
        setLaunchedTool(detail as WebToolDetail);
      } else {
        console.warn('Only Web Tools can be launched internally.');
        setSelectedItemLink(link);
      }
    } catch (err) {
      console.error('Failed to launch tool:', err);
    } finally {
      setIsLaunching(false);
    }
  }, [manifest]);

  const allTools = useMemo(() => {
    if (!data || !data.tools) return [];
    const { web = [], win = [], scripts, ai } = data.tools;
    const scriptTools = scripts ? Object.values(scripts).flat() : [];
    const aiTools = ai ? Object.values(ai).flat() : [];
    return [...web, ...win, ...scriptTools, ...aiTools].filter(Boolean);
  }, [data]);

  const allTags = useMemo(() => {
    const tags = new Set<string>();
    allTools.forEach(t => (t.tags || []).forEach(tag => tags.add(tag)));
    return ['All', ...Array.from(tags).sort()];
  }, [allTools]);

  const filteredTools = useMemo(() => {
    if (!data || !data.tools) return [];
    let sourceTools: Tool[] = [];

    switch (activeTab) {
        case ToolsSideTab.WebTools:
            sourceTools = data.tools.web || [];
            break;
        case ToolsSideTab.WindowsTools:
            sourceTools = data.tools.win || [];
            break;
        case ToolsSideTab.Scripts:
            const { py = [], ps = [], ahk = [] } = data.tools.scripts || {};
            sourceTools = [...py, ...ps, ...ahk];
            break;
        case ToolsSideTab.AITools:
            const { tools = [], prompts = [] } = data.tools.ai || {};
            sourceTools = [...tools, ...prompts];
            break;
        case ToolsSideTab.AllTools:
        default:
            sourceTools = allTools;
            break;
    }

    return sourceTools
    .filter(tool => showDebugContent || !tool.debug)
    .filter(tool => {
      const searchMatch = tool.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          tool.summary.toLowerCase().includes(searchTerm.toLowerCase());

      const tagMatch = tagFilter === 'All' || (tool.tags && tool.tags.includes(tagFilter));

      return searchMatch && tagMatch;
    });
  }, [data, searchTerm, tagFilter, activeTab, showDebugContent, allTools]);

  const featuredTools = useMemo(() => filteredTools.filter(t => t.featured), [filteredTools]);

  const renderListContent = () => (
    <div className="space-y-6">
      <div className="sticky top-2 z-10 flex justify-end -mr-2">
        <div className="flex items-center gap-2 bg-gray-900/70 backdrop-blur-md p-1.5 rounded-xl ring-1 ring-white/10 shadow-lg">
          <SearchAndFilter
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
            activeFilter={tagFilter}
            setActiveFilter={setTagFilter}
            filterOptions={allTags}
            filterTypeLabel="Tag"
          />
          <ViewSwitcher activeView={viewMode} setActiveView={setViewMode} />
        </div>
      </div>

      {featuredTools.length > 0 && (
        <div>
          <h2 className="text-2xl font-bold text-amber-300 mb-4 border-b-2 border-white/10 pb-2">Featured</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {featuredTools.map(item => (
              <ToolCard 
                key={item.link} 
                item={item} 
                manifest={manifest} 
                onViewDetails={handleViewDetails} 
                onLaunch={() => handleLaunchApp(item.link)}
              />
            ))}
          </div>
        </div>
      )}

      {filteredTools.length > 0 && (
         <div className={featuredTools.length > 0 ? "pt-6" : ""}>
             {featuredTools.length > 0 && <h2 className="text-2xl font-bold text-amber-300 mb-4 border-b-2 border-white/10 pb-2">All Tools</h2>}
             {viewMode === 'card' && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                    {filteredTools.map(item => (
                        <ToolCard 
                          key={item.link} 
                          item={item} 
                          manifest={manifest} 
                          onViewDetails={handleViewDetails} 
                          onLaunch={() => handleLaunchApp(item.link)}
                        />
                    ))}
                </div>
            )}
            {viewMode === 'list' && (
                <ListView items={filteredTools} type="tool" manifest={manifest} onViewDetails={handleViewDetails} />
            )}
            {viewMode === 'conveyor' && (
                 <p className="text-center py-10 text-gray-400">Conveyor view coming soon for tools!</p>
            )}
         </div>
      )}

      {filteredTools.length === 0 && (
        <div className="text-center py-10">
          <p className="text-gray-400">No tools found matching your criteria.</p>
        </div>
      )}
    </div>
  );

  const renderContent = () => {
    if (launchedTool) {
      return <ToolLauncher tool={launchedTool} manifest={manifest} onClose={() => setLaunchedTool(null)} />;
    }

    if (selectedItemLink) {
        return (
            <ToolDetailView 
                data={detailData}
                isLoading={isLoadingDetail}
                error={detailError}
                onBack={handleBackToList}
                onLaunch={() => handleLaunchApp(selectedItemLink)}
                manifest={manifest}
            />
        );
    }

    if (activeTab === ToolsSideTab.Introduction) {
        return <IntroductionTab htmlContent={data.intro} />;
    }

    return renderListContent();
  };

  return (
    <div className="flex flex-col md:flex-row gap-6 lg:gap-8 h-full py-8">
      {/* Overlay Loading for Launching */}
      {isLaunching && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-xl flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-amber-500/30 border-t-amber-500 rounded-full animate-spin mb-4" />
            <p className="text-amber-400 font-bold animate-pulse">Launching Creative App...</p>
        </div>
      )}

      {!launchedTool && (
        <aside className="w-full md:w-48 lg:w-56 flex-shrink-0">
          <SideNav<ToolsSideTab> tabs={sideTabs} activeTab={activeTab} setActiveTab={setActiveTab} />
        </aside>
      )}
      <div className="flex-grow min-w-0 overflow-y-auto overflow-x-hidden">
        <div className={`px-4 sm:px-6 lg:px-8 pb-28 ${launchedTool ? 'h-full flex flex-col' : ''}`}>
            {renderContent()}
        </div>
      </div>
    </div>
  );
};

