export interface GitHubContent {
  name: string;
  path: string;
  sha: string;
  size: number;
  url: string;
  html_url: string;
  git_url: string;
  download_url: string | null;
  type: 'file' | 'dir';
}

export interface GitTreeFile {
    path: string;
    mode: string;
    type: 'blob' | 'tree'; // blob is a file, tree is a directory
    sha: string;
    size?: number;
    url: string;
}

// Global cache to prevent redundant tree fetches
let globalTreeCache: GitTreeFile[] | null = null;
let isFetchingTree = false;
let treePromise: Promise<GitTreeFile[]> | null = null;

/**
 * Fetches the entire file tree for a branch recursively.
 * Uses a singleton pattern to ensure we only fetch this once per session.
 */
export const fetchGitTree = async (owner: string, repo: string, branch: string): Promise<GitTreeFile[]> => {
    if (globalTreeCache) return globalTreeCache;
    if (treePromise) return treePromise;

    const url = `https://api.github.com/repos/${owner}/${repo}/git/trees/${branch}?recursive=1`;

    treePromise = (async () => {
        try {
            const response = await fetch(url, {
                headers: { 'Accept': 'application/vnd.github.v3+json' },
                cache: 'no-cache'
            });
            if (!response.ok) {
                const errorData = await response.json().catch(() => ({ message: response.statusText }));
                throw new Error(`GitHub API error! status: ${response.status} - ${errorData.message || 'Unknown error'}`);
            }
            const data = await response.json();
            if (!data.tree || !Array.isArray(data.tree)) {
                throw new Error('Invalid response from GitHub Git Tree API.');
            }
            globalTreeCache = data.tree as GitTreeFile[];
            return globalTreeCache;
        } catch (error) {
            console.error(`Failed to fetch git tree from GitHub: ${url}`, error);
            treePromise = null; // Allow retry on failure
            throw error;
        }
    })();

    return treePromise;
};

/**
 * Gets the file extension from a filename.
 */
const getExtension = (filename: string): string => {
    return filename.slice((filename.lastIndexOf(".") - 1 >>> 0) + 2).toLowerCase();
};

/**
 * Fetches raw content from GitHub (usually not rate limited).
 */
export const fetchFromGitHubRaw = async (owner: string, repo: string, branch: string, path: string): Promise<string> => {
  const url = `https://raw.githubusercontent.com/${owner}/${repo}/${branch}/${path}`;
  try {
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status} - ${response.statusText}`);
    }
    return await response.text();
  } catch (error) {
    console.error(`Failed to fetch from GitHub: ${url}`, error);
    throw new Error('Could not fetch the file from GitHub.');
  }
};

/**
 * Optimized helper to get files in a directory using the cached tree.
 * This completely avoids hitting the /contents API.
 */
const getFilesFromTree = async (
    owner: string, 
    repo: string, 
    branch: string, 
    path: string, 
    options?: { fileTypes?: string | string[] }
): Promise<GitTreeFile[]> => {
    const tree = await fetchGitTree(owner, repo, branch);

    // Ensure path format
    const searchPath = path.endsWith('/') ? path : path + '/';

    let files = tree.filter(item => 
        item.type === 'blob' && 
        item.path.startsWith(searchPath) && 
        !item.path.slice(searchPath.length).includes('/') // Only immediate children
    );

    if (options?.fileTypes && options.fileTypes.length > 0) {
        const allowedTypes = (Array.isArray(options.fileTypes) ? options.fileTypes : [options.fileTypes])
            .map(ext => ext.toLowerCase().replace(/^\./, ''));

        files = files.filter(file => {
            const extension = getExtension(file.path);
            return extension && allowedTypes.includes(extension);
        });
    }
    return files;
};

/**
 * Fetches a random file metadata from the cached tree.
 * Used for background switching.
 */
export const getRandomFileInfoFromGitHubRepo = async (
    owner: string,
    repo: string,
    branch: string,
    path: string,
    options?: { fileTypes?: string | string[] }
): Promise<GitHubContent | null> => {
    try {
        const files = await getFilesFromTree(owner, repo, branch, path, options);
        if (files.length === 0) return null;

        const randomIndex = Math.floor(Math.random() * files.length);
        const selected = files[randomIndex];

        // Transform GitTreeFile to GitHubContent shape
        return {
            name: selected.path.split('/').pop() || '',
            path: selected.path,
            sha: selected.sha,
            size: selected.size || 0,
            url: selected.url,
            html_url: '',
            git_url: '',
            download_url: null,
            type: 'file'
        };
    } catch (err) {
        console.error('Error in getRandomFileInfoFromGitHubRepo:', err);
        return null;
    }
};

/**
 * Legacy support: fetches directory contents.
 * Now uses the tree if available to save API quota.
 */
export const getGitHubRepoDirectoryContents = async (
    owner: string,
    repo: string,
    branch: string,
    path: string,
    options?: { fileTypes?: string | string[] }
): Promise<GitHubContent[]> => {
    const files = await getFilesFromTree(owner, repo, branch, path, options);
    return files.map(selected => ({
        name: selected.path.split('/').pop() || '',
        path: selected.path,
        sha: selected.sha,
        size: selected.size || 0,
        url: selected.url,
        html_url: '',
        git_url: '',
        download_url: null,
        type: 'file'
    }));
};

