export interface GitHubContent {
  name: string;
  path: string;
  sha: string;
  size: number;
  url: string;
  html_url: string;
  git_url: string;
  download_url: string | null;
  type: 'file' | 'dir';
}

export interface GitTreeFile {
    path: string;
    mode: string;
    type: 'blob' | 'tree'; 
    sha: string;
    size?: number;
    url: string;
}

// Global cache to prevent redundant tree fetches
let globalTreeCache: GitTreeFile[] | null = null;
let treePromise: Promise<GitTreeFile[]> | null = null;

/**
 * Fetches the entire file tree for a branch recursively.
 * Uses a singleton pattern to ensure we only fetch this once per session.
 */
export const fetchGitTree = async (owner: string, repo: string, branch: string): Promise<GitTreeFile[]> => {
    if (globalTreeCache) return globalTreeCache;
    if (treePromise) return treePromise;

    const url = `https://api.github.com/repos/${owner}/${repo}/git/trees/${branch}?recursive=1`;

    treePromise = (async () => {
        try {
            const response = await fetch(url, {
                headers: { 'Accept': 'application/vnd.github.v3+json' },
                cache: 'force-cache'
            });
            if (!response.ok) {
                const errorData = await response.json().catch(() => ({ message: response.statusText }));
                // If we hit rate limit, we catch it but don't crash the whole app
                if (response.status === 403) {
                    console.error("GitHub API Rate Limit Exceeded. Falling back to local data where possible.");
                }
                throw new Error(`GitHub API error! status: ${response.status} - ${errorData.message || 'Unknown error'}`);
            }
            const data = await response.json();
            globalTreeCache = data.tree as GitTreeFile[];
            return globalTreeCache;
        } catch (error) {
            treePromise = null; // Allow retry
            throw error;
        }
    })();

    return treePromise;
};

const getExtension = (filename: string): string => {
    return filename.slice((filename.lastIndexOf(".") - 1 >>> 0) + 2).toLowerCase();
};

export const fetchFromGitHubRaw = async (owner: string, repo: string, branch: string, path: string): Promise<string> => {
  const url = `https://raw.githubusercontent.com/${owner}/${repo}/${branch}/${path}`;
  try {
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    return await response.text();
  } catch (error) {
    throw new Error('Could not fetch the file from GitHub.');
  }
};

const getFilesFromTree = async (
    owner: string, 
    repo: string, 
    branch: string, 
    path: string, 
    options?: { fileTypes?: string | string[] }
): Promise<GitTreeFile[]> => {
    const tree = await fetchGitTree(owner, repo, branch);
    const searchPath = path.endsWith('/') ? path : path + '/';

    let files = tree.filter(item => 
        item.type === 'blob' && 
        item.path.startsWith(searchPath) && 
        !item.path.slice(searchPath.length).includes('/')
    );

    if (options?.fileTypes) {
        const allowedTypes = (Array.isArray(options.fileTypes) ? options.fileTypes : [options.fileTypes])
            .map(ext => ext.toLowerCase().replace(/^\./, ''));
        files = files.filter(file => allowedTypes.includes(getExtension(file.path)));
    }
    return files;
};

export const getRandomFileInfoFromGitHubRepo = async (
    owner: string,
    repo: string,
    branch: string,
    path: string,
    options?: { fileTypes?: string | string[] }
): Promise<GitHubContent | null> => {
    try {
        const files = await getFilesFromTree(owner, repo, branch, path, options);
        if (files.length === 0) return null;
        const selected = files[Math.floor(Math.random() * files.length)];
        return {
            name: selected.path.split('/').pop() || '',
            path: selected.path,
            sha: selected.sha,
            size: selected.size || 0,
            url: selected.url,
            html_url: '', git_url: '', download_url: null, type: 'file'
        };
    } catch { return null; }
};

export const getGitHubRepoDirectoryContents = async (
    owner: string,
    repo: string,
    branch: string,
    path: string,
    options?: { fileTypes?: string | string[] }
): Promise<GitHubContent[]> => {
    const files = await getFilesFromTree(owner, repo, branch, path, options);
    return files.map(selected => ({
        name: selected.path.split('/').pop() || '',
        path: selected.path,
        sha: selected.sha,
        size: selected.size || 0,
        url: selected.url,
        html_url: '', git_url: '', download_url: null, type: 'file'
    }));
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { ToolsPageData, ToolsSideTab, Tool, ToolDetail, WebToolDetail } from '../types';
import { Manifest } from '../services/contentService';
import { fetchFromGitHubRaw } from '../modules/io/import-utils';
import SideNav from '../components/SideNav';
import IntroductionTab from '../components/music/IntroductionTab';
import SearchAndFilter from '../components/SearchAndFilter';
import ViewSwitcher, { ViewMode } from '../components/ViewSwitcher';
import ToolCard from '../components/tools/ToolCard';
import ToolDetailView from '../components/tools/ToolDetailView';
import ListView from '../components/music/ListView';
import ToolLauncher from '../components/tools/ToolLauncher';

interface ToolsPageProps {
  data: ToolsPageData;
  manifest: Manifest | null;
  showDebugContent: boolean;
}

const sideTabs: ToolsSideTab[] = [
  ToolsSideTab.Introduction,
  ToolsSideTab.AllTools,
  ToolsSideTab.WebTools,
  ToolsSideTab.WindowsTools,
  ToolsSideTab.Scripts,
  ToolsSideTab.AITools,
];

const SESSION_STORAGE_KEY = 'zikyinc_tools_active_tab';

const ToolsPage: React.FC<ToolsPageProps> = ({ data, manifest, showDebugContent }) => {
  const [activeTab, setActiveTab] = useState<ToolsSideTab>(() => {
    const savedTab = sessionStorage.getItem(SESSION_STORAGE_KEY);
    return (savedTab as ToolsSideTab) || ToolsSideTab.Introduction;
  });

  const [searchTerm, setSearchTerm] = useState('');
  const [tagFilter, setTagFilter] = useState('All');
  const [viewMode, setViewMode] = useState<ViewMode>('card');

  const [selectedItemLink, setSelectedItemLink] = useState<string | null>(null);
  const [detailData, setDetailData] = useState<ToolDetail | null>(null);
  const [isLoadingDetail, setIsLoadingDetail] = useState(false);
  const [detailError, setDetailError] = useState<string | null>(null);

  const [launchedTool, setLaunchedTool] = useState<WebToolDetail | null>(null);
  const [isLaunching, setIsLaunching] = useState(false);

  useEffect(() => {
    sessionStorage.setItem(SESSION_STORAGE_KEY, activeTab);
    setSelectedItemLink(null);
    setDetailData(null);
  }, [activeTab]);

  useEffect(() => {
    if (!selectedItemLink || !manifest) return;
    const fetchDetailData = async () => {
      setIsLoadingDetail(true);
      setDetailError(null);
      try {
        const { user, repo, branch } = manifest.git;
        const content = await fetchFromGitHubRaw(user, repo, branch, selectedItemLink);
        setDetailData(JSON.parse(content));
      } catch (err) {
        setDetailError(err instanceof Error ? err.message : 'Failed to load details.');
      } finally {
        setIsLoadingDetail(false);
      }
    };
    fetchDetailData();
  }, [selectedItemLink, manifest]);

  const handleViewDetails = useCallback((link: string) => {
    setLaunchedTool(null);
    setSelectedItemLink(link);
  }, []);

  const handleBackToList = useCallback(() => {
    setSelectedItemLink(null);
    setDetailData(null);
    setLaunchedTool(null);
  }, []);

  const handleLaunchApp = useCallback(async (link: string) => {
    if (!manifest) return;
    setIsLaunching(true);

    // FORCED BYPASS: We assume if the user clicked launch, they want the launcher.
    // We clear the detail link immediately so it can't show that view.
    setSelectedItemLink(null); 
    setDetailData(null);

    try {
      const { user, repo, branch } = manifest.git;
      const content = await fetchFromGitHubRaw(user, repo, branch, link);
      const detail = JSON.parse(content);

      // We set the launched tool. If app_path is missing, the ToolLauncher component
      // itself will handle showing an error, NOT this page switching back to cards.
      setLaunchedTool(detail as WebToolDetail);
    } catch (err) {
      console.error('Launch Error:', err);
      alert("Failed to load app configuration from GitHub.");
    } finally {
      setIsLaunching(false);
    }
  }, [manifest]);

  const allTools = useMemo(() => {
    if (!data?.tools) return [];
    const { web = [], win = [], scripts, ai } = data.tools;
    const scriptTools = scripts ? Object.values(scripts).flat() : [];
    const aiTools = ai ? Object.values(ai).flat() : [];
    return [...web, ...win, ...scriptTools, ...aiTools].filter(Boolean);
  }, [data]);

  const filteredTools = useMemo(() => {
    if (!data?.tools) return [];
    let sourceTools: Tool[] = [];
    switch (activeTab) {
        case ToolsSideTab.WebTools: sourceTools = data.tools.web || []; break;
        case ToolsSideTab.WindowsTools: sourceTools = data.tools.win || []; break;
        case ToolsSideTab.Scripts:
            const { py = [], ps = [], ahk = [] } = data.tools.scripts || {};
            sourceTools = [...py, ...ps, ...ahk];
            break;
        case ToolsSideTab.AITools:
            const { tools = [], prompts = [] } = data.tools.ai || {};
            sourceTools = [...tools, ...prompts];
            break;
        default: sourceTools = allTools; break;
    }
    return sourceTools
      .filter(tool => showDebugContent || !tool.debug)
      .filter(tool => {
        const searchMatch = tool.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            tool.summary.toLowerCase().includes(searchTerm.toLowerCase());
        const tagMatch = tagFilter === 'All' || (tool.tags && tool.tags.includes(tagFilter));
        return searchMatch && tagMatch;
      });
  }, [data, searchTerm, tagFilter, activeTab, showDebugContent, allTools]);

  const renderContent = () => {
    if (launchedTool) {
      return <ToolLauncher tool={launchedTool} manifest={manifest} onClose={() => setLaunchedTool(null)} />;
    }

    if (selectedItemLink) {
        return (
            <ToolDetailView 
                data={detailData}
                isLoading={isLoadingDetail}
                error={detailError}
                onBack={handleBackToList}
                onLaunch={() => handleLaunchApp(selectedItemLink)}
                manifest={manifest}
            />
        );
    }

    if (activeTab === ToolsSideTab.Introduction) {
        return <IntroductionTab htmlContent={data.intro} />;
    }

    return (
      <div className="space-y-6">
        <div className="sticky top-2 z-10 flex justify-end">
          <div className="flex items-center gap-2 bg-gray-900/70 backdrop-blur-md p-1.5 rounded-xl ring-1 ring-white/10 shadow-lg">
            <SearchAndFilter
              searchTerm={searchTerm} setSearchTerm={setSearchTerm}
              activeFilter={tagFilter} setActiveFilter={setTagFilter}
              filterOptions={['All', ...Array.from(new Set(allTools.flatMap(t => t.tags || []))).sort()]}
              filterTypeLabel="Tag"
            />
            <ViewSwitcher activeView={viewMode} setActiveView={setViewMode} />
          </div>
        </div>

        {viewMode === 'card' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredTools.map(item => (
              <ToolCard key={item.link} item={item} manifest={manifest} onViewDetails={handleViewDetails} onLaunch={() => handleLaunchApp(item.link)} />
            ))}
          </div>
        ) : (
          <ListView items={filteredTools} type="tool" manifest={manifest} onViewDetails={handleViewDetails} onLaunch={handleLaunchApp} />
        )}
      </div>
    );
  };

  return (
    <div className="flex flex-col md:flex-row gap-6 h-full py-8">
      {isLaunching && (
        <div className="fixed inset-0 z-[100] bg-black/95 flex flex-col items-center justify-center">
            <div className="w-12 h-12 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-4" />
            <p className="text-amber-400 font-bold tracking-widest uppercase text-xs animate-pulse">Initializing Production App...</p>
        </div>
      )}

      {!launchedTool && (
        <aside className="w-full md:w-48 lg:w-56 flex-shrink-0">
          <SideNav<ToolsSideTab> tabs={sideTabs} activeTab={activeTab} setActiveTab={setActiveTab} />
        </aside>
      )}
      <div className="flex-grow min-w-0 overflow-y-auto">
        <div className={`px-4 pb-28 ${launchedTool ? 'h-full flex flex-col' : ''}`}>
            {renderContent()}
        </div>
      </div>
    </div>
  );
};

export default ToolsPage;

import React from 'react';
import { Tool } from '../../types';
import { Manifest } from '../../services/contentService';
import GitHubImage from '../GitHubImage';
import MarkdownRenderer from '../MarkdownRenderer';

interface ToolCardProps {
  item: Tool;
  manifest: Manifest | null;
  onViewDetails: (link: string) => void;
  onLaunch?: () => void;
}

const ToolCard: React.FC<ToolCardProps> = ({ item, manifest, onViewDetails, onLaunch }) => {
  // Broad detection: if it's in the web category or looks like a web link, show launch button
  const isWebTool = 
    item.category?.toLowerCase().includes('web') || 
    item.tags?.some(t => t.toLowerCase() === 'web') ||
    item.link.toLowerCase().includes('qrg.json');

  const handleMainAction = () => {
    if (isWebTool && onLaunch) {
        onLaunch();
    } else {
        onViewDetails(item.link);
    }
  };

  return (
    <div className="bg-gray-900/50 backdrop-blur-lg rounded-2xl overflow-hidden ring-1 ring-white/10 shadow-2xl flex flex-col group glow-on-hover glow-primary transition-all duration-300 h-full">
      <div className="overflow-hidden relative cursor-pointer" onClick={handleMainAction}>
        <GitHubImage
            manifest={manifest}
            path={item.thumbnail}
            alt={item.name}
            className="w-full h-48 object-cover transition-transform duration-300 ease-in-out group-hover:scale-110"
            placeholderCat="tools"
        />
        {isWebTool && (
            <div className="absolute top-2 left-2 px-2 py-1 bg-amber-500 text-gray-900 text-[10px] font-black uppercase rounded shadow-lg">
                Web App
            </div>
        )}
      </div>
      <div className="flex-grow flex flex-col p-4">
        <h3 className="text-xl font-bold text-amber-400 mb-2 truncate" title={item.name}>{item.name}</h3>
        <div className="text-sm text-gray-300 flex-grow mb-4">
            <MarkdownRenderer markdown={item.summary} className="prose-sm line-clamp-3" />
        </div>

        <div className="mt-auto flex flex-col gap-2">
            {isWebTool && onLaunch && (
                <button 
                  onClick={(e) => { e.stopPropagation(); onLaunch(); }}
                  className="w-full px-4 py-3 text-sm font-black uppercase tracking-tight text-gray-900 bg-amber-400 rounded-xl hover:bg-amber-300 transition-all shadow-[0_0_15px_rgba(245,158,11,0.2)] transform active:scale-95"
                >
                  Launch App
                </button>
            )}
            <button 
              onClick={(e) => { e.stopPropagation(); onViewDetails(item.link); }}
              className={`w-full px-4 py-2 text-sm font-semibold text-gray-400 border border-white/5 rounded-xl hover:bg-white/5 transition-all ${!isWebTool ? 'bg-amber-400/10 text-amber-300 border-amber-400/20 py-3 font-bold uppercase' : ''}`}
            >
              {isWebTool ? 'View Specs' : 'View Details'}
            </button>
        </div>
      </div>
    </div>
  );
};

export default ToolCard;

import React, { useState, useEffect } from 'react';
import { WebToolDetail } from '../../types';
import { Manifest } from '../../services/contentService';

interface ToolLauncherProps {
    tool: WebToolDetail;
    manifest: Manifest | null;
    onClose: () => void;
}

const buildAssetUrl = (manifest: Manifest, path: string): string => {
    const { user, repo, branch } = manifest.git;
    return `https://raw.githubusercontent.com/${user}/${repo}/${branch}/${path}`;
};

const ToolLauncher: React.FC<ToolLauncherProps> = ({ tool, manifest, onClose }) => {
    const [launchUrl, setLaunchUrl] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!manifest) return;

        const initializeApp = async () => {
            setLoading(true);
            setError(null);

            // If it's a local file, we can point to it directly as it's within the project root
            if (tool.source_type === 'local') {
                setLaunchUrl(tool.app_path);
                setLoading(false);
                return;
            }

            // If it's a remote file (git), we MUST fetch it and use a Blob to bypass X-Frame-Options
            try {
                const remoteUrl = buildAssetUrl(manifest, tool.app_path);
                const response = await fetch(remoteUrl);

                if (!response.ok) throw new Error(`App source not found (Status: ${response.status})`);

                const html = await response.text();
                const blob = new Blob([html], { type: 'text/html' });
                const blobUrl = URL.createObjectURL(blob);

                setLaunchUrl(blobUrl);
            } catch (err) {
                console.error("Tool Launch Failed:", err);
                setError(err instanceof Error ? err.message : "Failed to load remote application code.");
            } finally {
                setLoading(false);
            }
        };

        initializeApp();

        // Cleanup the Blob URL when the component unmounts
        return () => {
            if (launchUrl && launchUrl.startsWith('blob:')) {
                URL.revokeObjectURL(launchUrl);
            }
        };
    }, [tool, manifest]);

    if (!manifest) return null;

    return (
        <div className="flex-grow flex flex-col bg-gray-950 rounded-2xl overflow-hidden ring-1 ring-white/10 shadow-3xl animate-fade-in-up relative">
            {/* HUD Header */}
            <div className="h-14 bg-gray-900/80 backdrop-blur-md border-b border-white/10 px-4 flex items-center justify-between z-10">
                <div className="flex items-center gap-3">
                    <div className={`w-2 h-2 rounded-full shadow-[0_0_8px_rgba(34,197,94,0.6)] ${loading ? 'bg-amber-500 animate-pulse' : error ? 'bg-red-500' : 'bg-green-500 animate-pulse'}`} />
                    <h2 className="text-amber-400 font-bold tracking-wider uppercase text-sm">{tool.name}</h2>
                    <span className="text-[10px] text-gray-500 font-mono hidden sm:inline">PROD_ENV // {tool.category}</span>
                </div>
                <button
                    onClick={onClose}
                    className="flex items-center gap-2 px-3 py-1 text-sm font-bold text-gray-400 hover:text-white hover:bg-white/5 rounded-md transition-all group"
                >
                    <span className="hidden sm:inline">Exit App</span>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 transition-transform group-hover:rotate-90" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                    </svg>
                </button>
            </div>

            {/* App Content Area */}
            <div className="flex-grow relative bg-white">
                {loading && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-950 z-20">
                        <div className="w-10 h-10 border-2 border-amber-500/20 border-t-amber-500 rounded-full animate-spin mb-4"></div>
                        <p className="text-amber-400 font-mono text-[10px] tracking-widest uppercase">Fetching Assets...</p>
                    </div>
                )}

                {error && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-900 text-center p-8 z-20">
                        <div className="text-red-500 text-5xl mb-4">⚠️</div>
                        <h3 className="text-xl font-bold text-white mb-2">Internal Boot Failure</h3>
                        <p className="text-gray-400 max-w-md">{error}</p>
                        <button onClick={onClose} className="mt-6 px-6 py-2 bg-gray-800 text-white rounded-lg hover:bg-gray-700 transition-colors">Return to Library</button>
                    </div>
                )}

                {launchUrl && !error && (
                    <iframe
                        src={launchUrl}
                        title={tool.name}
                        className="w-full h-full border-none"
                        sandbox="allow-scripts allow-same-origin allow-forms allow-popups"
                        loading="lazy"
                        onLoad={() => setLoading(false)}
                    />
                )}
            </div>

            {/* Footer / Status Bar */}
            <div className="h-6 bg-gray-900/90 border-t border-white/5 px-4 flex items-center justify-between">
                 <div className="flex gap-4 text-[9px] font-mono text-gray-500">
                    <span>STATUS: {error ? 'FAIL' : loading ? 'INIT' : 'ACTIVE'}</span>
                    <span>SOURCE: {tool.source_type?.toUpperCase()}</span>
                 </div>
                 <div className="text-[9px] font-mono text-amber-500 opacity-50">
                    CONTAINER_v1.0.5 // {new Date().toLocaleTimeString()}
                 </div>
            </div>
        </div>
    );
};

export default ToolLauncher;

import React, { useState, useEffect } from 'react';
import { WebToolDetail } from '../../types';
import { Manifest } from '../../services/contentService';

interface ToolLauncherProps {
    tool: WebToolDetail;
    manifest: Manifest | null;
    onClose: () => void;
}

/**
 * Robustly joins path segments for GitHub Raw URLs
 */
const buildGitHubUrl = (manifest: Manifest, path: string): string => {
    const { user, repo, branch } = manifest.git;
    // Ensure path doesn't start with a slash for the GitHub URL
    const cleanPath = path.startsWith('/') ? path.slice(1) : path;
    return `https://raw.githubusercontent.com/${user}/${repo}/${branch}/${cleanPath}`;
};

const ToolLauncher: React.FC<ToolLauncherProps> = ({ tool, manifest, onClose }) => {
    const [launchUrl, setLaunchUrl] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!manifest) return;

        const initializeApp = async () => {
            setLoading(true);
            setError(null);

            // DETECT LOCAL: If path starts with apps/ or /apps/, or source_type is explicitly local
            const isLocal = 
                tool.source_type === 'local' || 
                tool.app_path.startsWith('apps/') || 
                tool.app_path.startsWith('/apps/');

            if (isLocal) {
                // For local files, we want a leading slash so the browser treats it as absolute from root
                const localPath = tool.app_path.startsWith('/') ? tool.app_path : `/${tool.app_path}`;
                setLaunchUrl(localPath);
                setLoading(false);
                return;
            }

            // REMOTE LOGIC: Use Blob strategy to bypass GitHub's X-Frame-Options
            try {
                const remoteUrl = buildGitHubUrl(manifest, tool.app_path);
                const response = await fetch(remoteUrl);

                if (!response.ok) {
                    throw new Error(`Cloud source not found at: ${remoteUrl} (Status: ${response.status})`);
                }

                const html = await response.text();
                const blob = new Blob([html], { type: 'text/html' });
                const blobUrl = URL.createObjectURL(blob);

                setLaunchUrl(blobUrl);
            } catch (err) {
                console.error("Tool Launch Failed:", err);
                setError(err instanceof Error ? err.message : "Failed to establish secure connection to remote app source.");
            } finally {
                setLoading(false);
            }
        };

        initializeApp();

        return () => {
            if (launchUrl && launchUrl.startsWith('blob:')) {
                URL.revokeObjectURL(launchUrl);
            }
        };
    }, [tool, manifest]);

    if (!manifest) return null;

    return (
        <div className="flex-grow flex flex-col bg-gray-950 rounded-2xl overflow-hidden ring-1 ring-white/10 shadow-3xl animate-fade-in-up relative">
            {/* Control Bar */}
            <div className="h-14 bg-gray-900/90 backdrop-blur-xl border-b border-white/10 px-4 flex items-center justify-between z-10">
                <div className="flex items-center gap-3">
                    <div className={`w-2 h-2 rounded-full ${loading ? 'bg-amber-500 animate-pulse' : error ? 'bg-red-500' : 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]'}`} />
                    <h2 className="text-amber-400 font-bold tracking-wider uppercase text-sm truncate max-w-[150px] sm:max-w-none">{tool.name}</h2>
                </div>
                <button
                    onClick={onClose}
                    className="flex items-center gap-2 px-3 py-1.5 text-xs font-black uppercase tracking-widest text-gray-400 hover:text-white hover:bg-white/5 border border-white/5 rounded-lg transition-all"
                >
                    <span className="hidden sm:inline">Close System</span>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                    </svg>
                </button>
            </div>

            {/* Viewport */}
            <div className="flex-grow relative bg-white overflow-hidden">
                {loading && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-950 z-20">
                        <div className="w-12 h-12 border-4 border-amber-500/10 border-t-amber-500 rounded-full animate-spin mb-6" />
                        <div className="text-amber-400 font-mono text-[10px] tracking-[0.3em] uppercase animate-pulse">Initializing Virtual Sandbox...</div>
                    </div>
                )}

                {error && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-900 text-center p-6 z-20">
                        <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-6 ring-1 ring-red-500/30">
                             <span className="text-red-500 text-3xl">!</span>
                        </div>
                        <h3 className="text-xl font-bold text-white mb-2 uppercase tracking-tighter">Container Failure</h3>
                        <p className="text-gray-400 max-w-sm text-sm leading-relaxed mb-8">{error}</p>
                        <button onClick={onClose} className="px-8 py-3 bg-white/5 text-gray-300 border border-white/10 rounded-xl hover:bg-white/10 transition-all font-bold uppercase text-xs tracking-widest">Return to Base</button>
                    </div>
                )}

                {launchUrl && !error && (
                    <iframe
                        src={launchUrl}
                        title={tool.name}
                        className="w-full h-full border-none"
                        sandbox="allow-scripts allow-same-origin allow-forms allow-popups"
                        onLoad={() => setLoading(false)}
                    />
                )}
            </div>

            {/* Status Strip */}
            <div className="h-6 bg-black border-t border-white/5 px-4 flex items-center justify-between">
                 <div className="flex gap-4 text-[8px] font-mono font-bold text-gray-500">
                    <span>MODE: {launchUrl?.startsWith('blob:') ? 'SECURE_REMOTE' : 'LOCAL_DIRECT'}</span>
                    <span>PATH: {tool.app_path}</span>
                 </div>
                 <div className="text-[8px] font-mono text-amber-500/40 uppercase tracking-widest">
                    ZIKY_OS_V1
                 </div>
            </div>
        </div>
    );
};

export default ToolLauncher;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { ToolsPageData, ToolsSideTab, Tool, ToolDetail, WebToolDetail } from '../types';
import { Manifest } from '../services/contentService';
import { fetchFromGitHubRaw } from '../modules/io/import-utils';
import SideNav from '../components/SideNav';
import IntroductionTab from '../components/music/IntroductionTab';
import SearchAndFilter from '../components/SearchAndFilter';
import ViewSwitcher, { ViewMode } from '../components/ViewSwitcher';
import ToolCard from '../components/tools/ToolCard';
import ToolDetailView from '../components/tools/ToolDetailView';
import ListView from '../components/music/ListView';
import ToolLauncher from '../components/tools/ToolLauncher';

interface ToolsPageProps {
  data: ToolsPageData;
  manifest: Manifest | null;
  showDebugContent: boolean;
}

const sideTabs: ToolsSideTab[] = [
  ToolsSideTab.Introduction,
  ToolsSideTab.AllTools,
  ToolsSideTab.WebTools,
  ToolsSideTab.WindowsTools,
  ToolsSideTab.Scripts,
  ToolsSideTab.AITools,
];

const SESSION_STORAGE_KEY = 'zikyinc_tools_active_tab';

const ToolsPage: React.FC<ToolsPageProps> = ({ data, manifest, showDebugContent }) => {
  const [activeTab, setActiveTab] = useState<ToolsSideTab>(() => {
    const savedTab = sessionStorage.getItem(SESSION_STORAGE_KEY);
    return (savedTab as ToolsSideTab) || ToolsSideTab.Introduction;
  });

  const [searchTerm, setSearchTerm] = useState('');
  const [tagFilter, setTagFilter] = useState('All');
  const [viewMode, setViewMode] = useState<ViewMode>('card');

  const [selectedItemLink, setSelectedItemLink] = useState<string | null>(null);
  const [detailData, setDetailData] = useState<ToolDetail | null>(null);
  const [isLoadingDetail, setIsLoadingDetail] = useState(false);
  const [detailError, setDetailError] = useState<string | null>(null);

  const [launchedTool, setLaunchedTool] = useState<WebToolDetail | null>(null);
  const [isLaunching, setIsLaunching] = useState(false);

  useEffect(() => {
    sessionStorage.setItem(SESSION_STORAGE_KEY, activeTab);
    setSelectedItemLink(null);
    setDetailData(null);
  }, [activeTab]);

  /**
   * Helper to fetch data either locally or from GitHub
   */
  const fetchToolConfig = useCallback(async (link: string): Promise<any> => {
      // 1. Try local first (important for dev testing)
      try {
          const localResponse = await fetch(`/${link}`);
          if (localResponse.ok) {
              const localText = await localResponse.text();
              if (localText && localText.trim().startsWith('{')) {
                  return JSON.parse(localText);
              }
          }
      } catch (e) {
          // Silent fail on local, move to GitHub
      }

      // 2. Fallback to GitHub
      if (!manifest) throw new Error("Manifest not loaded");
      const { user, repo, branch } = manifest.git;
      const remoteContent = await fetchFromGitHubRaw(user, repo, branch, link);
      return JSON.parse(remoteContent);
  }, [manifest]);

  useEffect(() => {
    if (!selectedItemLink) return;
    const loadDetail = async () => {
      setIsLoadingDetail(true);
      setDetailError(null);
      try {
        const detail = await fetchToolConfig(selectedItemLink);
        setDetailData(detail);
      } catch (err) {
        setDetailError(err instanceof Error ? err.message : 'Failed to load details.');
      } finally {
        setIsLoadingDetail(false);
      }
    };
    loadDetail();
  }, [selectedItemLink, fetchToolConfig]);

  const handleViewDetails = useCallback((link: string) => {
    setLaunchedTool(null);
    setSelectedItemLink(link);
  }, []);

  const handleBackToList = useCallback(() => {
    setSelectedItemLink(null);
    setDetailData(null);
    setLaunchedTool(null);
  }, []);

  const handleLaunchApp = useCallback(async (link: string) => {
    setIsLaunching(true);
    setSelectedItemLink(null); 
    setDetailData(null);

    try {
      const detail = await fetchToolConfig(link);
      setLaunchedTool(detail as WebToolDetail);
    } catch (err) {
      console.error('Launch Error:', err);
      alert(`Boot Sequence Aborted: ${err instanceof Error ? err.message : 'Unknown link error'}`);
    } finally {
      setIsLaunching(false);
    }
  }, [fetchToolConfig]);

  const allTools = useMemo(() => {
    if (!data?.tools) return [];
    const { web = [], win = [], scripts, ai } = data.tools;
    const scriptTools = scripts ? Object.values(scripts).flat() : [];
    const aiTools = ai ? Object.values(ai).flat() : [];
    return [...web, ...win, ...scriptTools, ...aiTools].filter(Boolean);
  }, [data]);

  const filteredTools = useMemo(() => {
    if (!data?.tools) return [];
    let sourceTools: Tool[] = [];
    switch (activeTab) {
        case ToolsSideTab.WebTools: sourceTools = data.tools.web || []; break;
        case ToolsSideTab.WindowsTools: sourceTools = data.tools.win || []; break;
        case ToolsSideTab.Scripts:
            const { py = [], ps = [], ahk = [] } = data.tools.scripts || {};
            sourceTools = [...py, ...ps, ...ahk];
            break;
        case ToolsSideTab.AITools:
            const { tools = [], prompts = [] } = data.tools.ai || {};
            sourceTools = [...tools, ...prompts];
            break;
        default: sourceTools = allTools; break;
    }
    return sourceTools
      .filter(tool => showDebugContent || !tool.debug)
      .filter(tool => {
        const searchMatch = tool.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            tool.summary.toLowerCase().includes(searchTerm.toLowerCase());
        const tagMatch = tagFilter === 'All' || (tool.tags && tool.tags.includes(tagFilter));
        return searchMatch && tagMatch;
      });
  }, [data, searchTerm, tagFilter, activeTab, showDebugContent, allTools]);

  const renderContent = () => {
    if (launchedTool) {
      return <ToolLauncher tool={launchedTool} manifest={manifest} onClose={() => setLaunchedTool(null)} />;
    }

    if (selectedItemLink) {
        return (
            <ToolDetailView 
                data={detailData}
                isLoading={isLoadingDetail}
                error={detailError}
                onBack={handleBackToList}
                onLaunch={() => handleLaunchApp(selectedItemLink)}
                manifest={manifest}
            />
        );
    }

    if (activeTab === ToolsSideTab.Introduction) {
        return <IntroductionTab htmlContent={data.intro} />;
    }

    return (
      <div className="space-y-6">
        <div className="sticky top-2 z-10 flex justify-end">
          <div className="flex items-center gap-2 bg-gray-900/70 backdrop-blur-md p-1.5 rounded-xl ring-1 ring-white/10 shadow-lg">
            <SearchAndFilter
              searchTerm={searchTerm} setSearchTerm={setSearchTerm}
              activeFilter={tagFilter} setActiveFilter={setTagFilter}
              filterOptions={['All', ...Array.from(new Set(allTools.flatMap(t => t.tags || []))).sort()]}
              filterTypeLabel="Tag"
            />
            <ViewSwitcher activeView={viewMode} setActiveView={setViewMode} />
          </div>
        </div>

        {viewMode === 'card' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredTools.map(item => (
              <ToolCard key={item.link} item={item} manifest={manifest} onViewDetails={handleViewDetails} onLaunch={() => handleLaunchApp(item.link)} />
            ))}
          </div>
        ) : (
          <ListView items={filteredTools} type="tool" manifest={manifest} onViewDetails={handleViewDetails} onLaunch={handleLaunchApp} />
        )}
      </div>
    );
  };

  return (
    <div className="flex flex-col md:flex-row gap-6 h-full py-8">
      {isLaunching && (
        <div className="fixed inset-0 z-[100] bg-black/95 flex flex-col items-center justify-center">
            <div className="w-12 h-12 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-4" />
            <p className="text-amber-400 font-bold tracking-widest uppercase text-xs animate-pulse">Initializing Production App...</p>
        </div>
      )}

      {!launchedTool && (
        <aside className="w-full md:w-48 lg:w-56 flex-shrink-0">
          <SideNav<ToolsSideTab> tabs={sideTabs} activeTab={activeTab} setActiveTab={setActiveTab} />
        </aside>
      )}
      <div className="flex-grow min-w-0 overflow-y-auto">
        <div className={`px-4 pb-28 ${launchedTool ? 'h-full flex flex-col' : ''}`}>
            {renderContent()}
        </div>
      </div>
    </div>
  );
};

export default ToolsPage;

