  const [launchedTool, setLaunchedTool] = useState<WebToolDetail | null>(null);
  const [isLaunching, setIsLaunching] = useState(false);

  useEffect(() => {
    sessionStorage.setItem(SESSION_STORAGE_KEY, activeTab);
    setSelectedItemLink(null);
    setDetailData(null);
  }, [activeTab]);

  /**
   * Robustly fetch tool metadata.
   * Checks local paths first, ensuring valid JSON before returning.
   */
  const fetchToolConfig = useCallback(async (link: string): Promise<any> => {
      // 1. Determine local search candidates
      const cleanLink = link.startsWith('/') ? link.slice(1) : link;
      const candidates = [`/${cleanLink}`];

      // If path mentions Website/lib but we are looking in data/lib or vice-versa
      if (cleanLink.startsWith('data/')) candidates.push(`/${cleanLink.replace('data/', 'Website/')}`);
      if (cleanLink.startsWith('Website/')) candidates.push(`/${cleanLink.replace('Website/', 'data/')}`);

      for (const url of candidates) {
          try {
              const res = await fetch(url);
              if (res.ok) {
                  const text = await res.text();
                  if (text && text.trim().startsWith('{')) {
                      const json = JSON.parse(text);
                      // Validation: A valid web tool must have an app_path
                      if (json.category === 'Web Tool' && !json.app_path) {
                          console.warn(`Local file at ${url} is missing app_path property.`);
                          continue; 
                      }
                      return json;
                  }
              }
          } catch (e) {
              console.warn(`Failed to fetch tool metadata from local candidate ${url}:`, e);
          }
      }

      // 2. Fallback to GitHub (Cloud)
      if (!manifest) throw new Error("Connection Failure: Manifest not loaded.");
      const { user, repo, branch } = manifest.git;

      try {
          const remoteContent = await fetchFromGitHubRaw(user, repo, branch, cleanLink);
          return JSON.parse(remoteContent);
      } catch (e) {
          throw new Error(`Cloud connection failed for: ${cleanLink}. Ensure the file exists in the repo.`);
      }
  }, [manifest]);

  useEffect(() => {
    if (!selectedItemLink) return;
    const loadDetail = async () => {
      setIsLoadingDetail(true);
      setDetailError(null);
      try {
        const detail = await fetchToolConfig(selectedItemLink);
        setDetailData(detail);
      } catch (err) {
        setDetailError(err instanceof Error ? err.message : 'Failed to load details.');
      } finally {
        setIsLoadingDetail(false);
      }
    };
    loadDetail();
  }, [selectedItemLink, fetchToolConfig]);

  const handleViewDetails = useCallback((link: string) => {
    setLaunchedTool(null);
    setSelectedItemLink(link);
  }, []);

  const handleBackToList = useCallback(() => {
    setSelectedItemLink(null);
    setDetailData(null);
    setLaunchedTool(null);
  }, []);

  const handleLaunchApp = useCallback(async (link: string) => {
    setIsLaunching(true);
    setSelectedItemLink(null); 
    setDetailData(null);

    try {
      const detail = await fetchToolConfig(link);
      if (!detail || !detail.app_path) {
          throw new Error("Metadata Corrupted: Executable path (app_path) missing in configuration.");
      }
      setLaunchedTool(detail as WebToolDetail);
    } catch (err) {
      console.error('Launch Sequence Failure:', err);
      alert(`Boot Sequence Aborted: ${err instanceof Error ? err.message : 'System Link Error'}`);
    } finally {
      setIsLaunching(false);
    }
  }, [fetchToolConfig]);

  const allTools = useMemo(() => {
    if (!data?.tools) return [];
    const { web = [], win = [], scripts, ai } = data.tools;
    const scriptTools = scripts ? Object.values(scripts).flat() : [];
    const aiTools = ai ? Object.values(ai).flat() : [];
    return [...web, ...win, ...scriptTools, ...aiTools].filter(Boolean);
  }, [data]);

  const filteredTools = useMemo(() => {
    if (!data?.tools) return [];
    let sourceTools: Tool[] = [];
    switch (activeTab) {
        case ToolsSideTab.WebTools: sourceTools = data.tools.web || []; break;
        case ToolsSideTab.WindowsTools: sourceTools = data.tools.win || []; break;
        case ToolsSideTab.Scripts:
            const { py = [], ps = [], ahk = [] } = data.tools.scripts || {};
            sourceTools = [...py, ...ps, ...ahk];
            break;
        case ToolsSideTab.AITools:
            const { tools = [], prompts = [] } = data.tools.ai || {};
            sourceTools = [...tools, ...prompts];
            break;
        default: sourceTools = allTools; break;
    }
    return sourceTools
      .filter(tool => showDebugContent || !tool.debug)
      .filter(tool => {
        const searchMatch = tool.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            tool.summary.toLowerCase().includes(searchTerm.toLowerCase());
        const tagMatch = tagFilter === 'All' || (tool.tags && tool.tags.includes(tagFilter));
        return searchMatch && tagMatch;
      });
  }, [data, searchTerm, tagFilter, activeTab, showDebugContent, allTools]);

  const renderContent = () => {
    if (launchedTool) {
      return <ToolLauncher tool={launchedTool} manifest={manifest} onClose={() => setLaunchedTool(null)} />;
    }

    if (selectedItemLink) {
        return (
            <ToolDetailView 
                data={detailData}
                isLoading={isLoadingDetail}
                error={detailError}
                onBack={handleBackToList}
                onLaunch={() => handleLaunchApp(selectedItemLink)}
                manifest={manifest}
            />
        );
    }

    if (activeTab === ToolsSideTab.Introduction) {
        return <IntroductionTab htmlContent={data.intro} />;
    }

    return (
      <div className="space-y-6">
        <div className="sticky top-2 z-10 flex justify-end">
          <div className="flex items-center gap-2 bg-gray-900/70 backdrop-blur-md p-1.5 rounded-xl ring-1 ring-white/10 shadow-lg">
            <SearchAndFilter
              searchTerm={searchTerm} setSearchTerm={setSearchTerm}
              activeFilter={tagFilter} setActiveFilter={setTagFilter}
              filterOptions={['All', ...Array.from(new Set(allTools.flatMap(t => t.tags || []))).sort()]}
              filterTypeLabel="Tag"
            />
            <ViewSwitcher activeView={viewMode} setActiveView={setViewMode} />
          </div>
        </div>

        {viewMode === 'card' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredTools.map(item => (
              <ToolCard key={item.link} item={item} manifest={manifest} onViewDetails={handleViewDetails} onLaunch={() => handleLaunchApp(item.link)} />
            ))}
          </div>
        ) : (
          <ListView items={filteredTools} type="tool" manifest={manifest} onViewDetails={handleViewDetails} onLaunch={handleLaunchApp} />
        )}
      </div>
    );
  };

  return (
    <div className="flex flex-col md:flex-row gap-6 h-full py-8">
      {isLaunching && (
        <div className="fixed inset-0 z-[100] bg-black/95 flex flex-col items-center justify-center">
            <div className="w-12 h-12 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-4" />
            <p className="text-amber-400 font-bold tracking-widest uppercase text-xs animate-pulse">Initializing Production App...</p>
        </div>
      )}

      {!launchedTool && (
        <aside className="w-full md:w-48 lg:w-56 flex-shrink-0">
          <SideNav<ToolsSideTab> tabs={sideTabs} activeTab={activeTab} setActiveTab={setActiveTab} />
        </aside>
      )}
      <div className="flex-grow min-w-0 overflow-y-auto">
        <div className={`px-4 pb-28 ${launchedTool ? 'h-full flex flex-col' : ''}`}>
            {renderContent()}
        </div>
      </div>
    </div>
  );
};

