import React, { useState, useEffect } from 'react';
import { WebToolDetail } from '../../types';
import { Manifest } from '../../services/contentService';

interface ToolLauncherProps {
    tool: WebToolDetail;
    manifest: Manifest | null;
    onClose: () => void;
}

/**
 * Robustly joins path segments for GitHub Raw URLs
 */
const buildGitHubUrl = (manifest: Manifest, path: string): string => {
    const { user, repo, branch } = manifest.git;
    if (!path) return '';
    // Ensure path doesn't start with a slash for the GitHub URL
    const cleanPath = path.startsWith('/') ? path.slice(1) : path;
    return `https://raw.githubusercontent.com/${user}/${repo}/${branch}/${cleanPath}`;
};

const ToolLauncher: React.FC<ToolLauncherProps> = ({ tool, manifest, onClose }) => {
    const [launchUrl, setLaunchUrl] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!manifest) return;

        const initializeApp = async () => {
            setLoading(true);
            setError(null);

            // Safety check for path
            const path = tool?.app_path;
            if (!path) {
                console.error("Launcher received invalid tool object:", tool);
                setError(`System Failure: Tool configuration for "${tool?.name || 'Unknown'}" is missing an executable path.`);
                setLoading(false);
                return;
            }

            // DETECT LOCAL: Check if file exists in project folder
            const isLocal = 
                tool.source_type === 'local' || 
                path.startsWith('apps/') || 
                path.startsWith('/apps/');

            if (isLocal) {
                // Ensure local path is absolute from the root for the iframe
                const localPath = path.startsWith('/') ? path : `/${path}`;
                setLaunchUrl(localPath);

                // For local files, we give it a 3s timeout to trigger onLoad, 
                // otherwise we force-hide the loader just in case.
                const timer = setTimeout(() => setLoading(false), 3000);
                return () => clearTimeout(timer);
            }

            // REMOTE LOGIC: Use Blob strategy to bypass GitHub's X-Frame-Options
            try {
                const remoteUrl = buildGitHubUrl(manifest, path);
                const response = await fetch(remoteUrl);

                if (!response.ok) {
                    throw new Error(`Cloud source not found at: ${remoteUrl} (Status: ${response.status})`);
                }

                const html = await response.text();
                // Basic HTML validation
                if (!html.toLowerCase().includes('<!doctype') && !html.toLowerCase().includes('<html')) {
                    throw new Error("Cloud source returned invalid HTML format.");
                }

                const blob = new Blob([html], { type: 'text/html' });
                const blobUrl = URL.createObjectURL(blob);

                setLaunchUrl(blobUrl);
            } catch (err) {
                console.error("Tool Launch Failed:", err);
                setError(err instanceof Error ? err.message : "Failed to establish secure connection to remote app source.");
                setLoading(false);
            }
        };

        initializeApp();

        return () => {
            if (launchUrl && launchUrl.startsWith('blob:')) {
                URL.revokeObjectURL(launchUrl);
            }
        };
    }, [tool, manifest]);

    if (!manifest) return null;

    return (
        <div className="flex-grow flex flex-col bg-gray-950 rounded-2xl overflow-hidden ring-1 ring-white/10 shadow-3xl animate-fade-in-up relative">
            {/* Control Bar */}
            <div className="h-14 bg-gray-900/90 backdrop-blur-xl border-b border-white/10 px-4 flex items-center justify-between z-10">
                <div className="flex items-center gap-3">
                    <div className={`w-2 h-2 rounded-full ${loading ? 'bg-amber-500 animate-pulse' : error ? 'bg-red-500' : 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]'}`} />
                    <h2 className="text-amber-400 font-bold tracking-wider uppercase text-sm truncate max-w-[150px] sm:max-w-none">{tool.name}</h2>
                </div>
                <button
                    onClick={onClose}
                    className="flex items-center gap-2 px-3 py-1.5 text-xs font-black uppercase tracking-widest text-gray-400 hover:text-white hover:bg-white/5 border border-white/5 rounded-lg transition-all"
                >
                    <span className="hidden sm:inline">Close System</span>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                    </svg>
                </button>
            </div>

            {/* Viewport */}
            <div className="flex-grow relative bg-white overflow-hidden">
                {loading && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-950 z-20">
                        <div className="w-12 h-12 border-4 border-amber-500/10 border-t-amber-500 rounded-full animate-spin mb-6" />
                        <div className="text-amber-400 font-mono text-[10px] tracking-[0.3em] uppercase animate-pulse">Initializing Virtual Sandbox...</div>
                    </div>
                )}

                {error && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-900 text-center p-6 z-20">
                        <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-6 ring-1 ring-red-500/30">
                             <span className="text-red-500 text-3xl">!</span>
                        </div>
                        <h3 className="text-xl font-bold text-white mb-2 uppercase tracking-tighter">Container Failure</h3>
                        <p className="text-gray-400 max-w-sm text-sm leading-relaxed mb-8">{error}</p>
                        <button onClick={onClose} className="px-8 py-3 bg-white/5 text-gray-300 border border-white/10 rounded-xl hover:bg-white/10 transition-all font-bold uppercase text-xs tracking-widest">Return to Base</button>
                    </div>
                )}

                {launchUrl && !error && (
                    <iframe
                        src={launchUrl}
                        title={tool.name}
                        className="w-full h-full border-none"
                        sandbox="allow-scripts allow-same-origin allow-forms allow-popups"
                        onLoad={() => setLoading(false)}
                    />
                )}
            </div>

            {/* Status Strip */}
            <div className="h-6 bg-black border-t border-white/5 px-4 flex items-center justify-between">
                 <div className="flex gap-4 text-[8px] font-mono font-bold text-gray-500">
                    <span>MODE: {launchUrl?.startsWith('blob:') ? 'SECURE_REMOTE' : 'LOCAL_DIRECT'}</span>
                    <span>PATH: {tool.app_path || 'UNDEFINED'}</span>
                 </div>
                 <div className="text-[8px] font-mono text-amber-500/40 uppercase tracking-widest">
                    ZIKY_OS_V1
                 </div>
            </div>
        </div>
    );
};

